function t(n,r="USD"){return new Intl.NumberFormat("en-US",{style:"currency",currency:r,maximumFractionDigits:2}).format(n??0)}function e(n,r="USD"){return new Intl.NumberFormat("en-US",{style:"currency",currency:r,notation:"compact",maximumFractionDigits:1}).format(n??0)}function o(n){return n?new Intl.DateTimeFormat("en-US",{day:"2-digit",month:"short",year:"numeric"}).format(new Date(n)):"\u2014"}function i(n){return n?n.replace(/_/g," ").split(" ").filter(Boolean).map(r=>r.charAt(0).toUpperCase()+r.slice(1)).join(" "):"\u2014"}export{t as a,e as b,o as c,i as d};
